var now = new Date();
var dayOfWeek = now.getDay();
var isWeekend = (dayOfWeek === 0 || dayOfWeek === 6);
if (isWeekend) {
    $ivr.setObject("dayType", "休日");
    $runner.setResult("休日");
} else {
    $ivr.setObject("dayType", "営業日");
    $runner.setResult("営業日");
}

